// // This module selects between two inputs based on the selector 'b'. If 'b' is 0, it outputs 'a'; otherwise, it outputs 'b'.
module mux2 (
	   input a,
	   input b,
	   output reg q);

   always @ (/*AS*/a, b) begin
     if (b == 1) begin
       q = a;
     end else begin
       q = b;
     end
   end
endmodule
